:root {
  /* ==========================================
     我方气泡 
  ========================================== */
  --bubble-me-bg: #DEE8F4;               /* 变更为烟雨蓝 */
  --bubble-me-bg-gradient: initial;
  --bubble-me-color: #354454;            /* 文字适配为曜石蓝灰 */
  --bubble-me-border: none;
  --bubble-me-shadow: 0 1px 3px rgba(107, 125, 143, 0.12);
  --bubble-me-link-color: #6B7D8F;       

  /* 1. 缩小整体与高度 */
  --bubble-me-font-size: 14px;
  --bubble-me-line-height: 1.35;
  --bubble-me-padding: 7px 12px;

  /* 2. 方圆形外观 */
  --bubble-me-radius: 12px;
  --bubble-me-radius-first: 12px 12px 4px 12px;
  --bubble-me-radius-mid: 12px 4px 4px 12px;
  --bubble-me-radius-last: 12px 4px 12px 12px;

  /* ==========================================
     对方气泡 (白色、雨丝蓝灰边框、缩小、方圆)
  ========================================== */
  --bubble-them-bg: #FFFFFF;
  --bubble-them-bg-gradient: initial;
  --bubble-them-color: #354454;          
  --bubble-them-border: 1px solid #E2EAF2; /* 边框变极浅雨丝蓝灰 */
  --bubble-them-shadow: 0 1px 2px rgba(107, 125, 143, 0.08);
  --bubble-them-link-color: #6B7D8F;

  /* 1. 缩小整体与高度 */
  --bubble-them-font-size: 14px;
  --bubble-them-line-height: 1.35;
  --bubble-them-padding: 7px 12px;

  /* 2. 方圆形外观 */
  --bubble-them-radius: 12px;
  --bubble-them-radius-first: 12px 12px 12px 4px;
  --bubble-them-radius-mid: 4px 12px 12px 4px;
  --bubble-them-radius-last: 4px 12px 12px 12px;

  /* ==========================================
     相关组件同步缩小与适配
  ========================================== */
  --translation-btn-color: #6B7D8F;
  --translation-text-color: #4A5B6E;
  --translation-bg: rgba(222, 232, 244, 0.4);
  --translation-size: 12.5px;
  --translation-padding: 6px 10px;

  --voice-me-color: #354454;             /* 我方语音图标 */
  --voice-me-bar-active: #354454;        /* 我方波形 */
  --voice-me-bar-inactive: rgba(53, 68, 84, 0.15);
  --voice-them-color: #354454;           /* 对方语音图标 */
  --voice-them-bar-active: #6B7D8F;      /* 对方波形 */
  --voice-them-bar-inactive: #E2EAF2;

  --plain-avatar-radius: 12px;
  --avatar-radius: 12px;
}

/* ==========================================
   一、头像显示逻辑 (隐藏时保留占位，气泡完美对齐)
========================================== */
.msg-avatar-me-container {
  visibility: hidden !important;
}
.msg-avatar-me-container.is-last,
.msg-avatar-me-container.is-single {
  visibility: visible !important;
}

.msg-avatar-them-container {
  visibility: hidden !important;
}
.msg-avatar-them-container.is-first,
.msg-avatar-them-container.is-single {
  visibility: visible !important;
}

/* ==========================================
   二、【我方头像】对齐与上下左右微调
========================================== */
.msg-avatar-me-container {
  align-self: flex-end !important;
  position: relative !important;
  left: -30px !important;
  top: 40px !important;
  margin-left: 10px !important; 
  overflow: visible !important;          
}

/* ==========================================
   三、【对方头像】对齐与上下左右微调
========================================== */
.msg-avatar-them-container {
  position: relative !important;
  left: 30px !important;
  top: -40px !important;
  margin-right: 10px !important;
  overflow: visible !important;          
}

/* ==========================================
   四、双方消息间距调整 (换人发言时较宽)
========================================= */
.msg-bubble-wrapper.is-last,
.msg-bubble-wrapper.is-single {
  margin-bottom: 30px !important; 
}

/* ==========================================
   五、头像：方圆形 + 白色边框 + 可旋转超大双层底框 (双层独立阴影)
========================================== */
.msg-avatar-me-inner,
.msg-avatar-them-inner,
.msg-avatar-custom {
  border-radius: 12px !important;
  border: 2px solid #FFFFFF !important;    
  box-shadow: 0 2px 6px rgba(107, 125, 143, 0.15) !important; 
  box-sizing: border-box !important;
  position: relative !important;
  z-index: 3 !important;                   
}

.msg-avatar-me-container::before,
.msg-avatar-them-container::before {
  content: "";
  position: absolute;
  top: -1px !important;
  left: -1px !important;
  right: -1px !important;
  bottom: -1px !important;

  border-radius: 14px !important;          
  background: #FFFFFF !important;          
  border: 1px solid #EBF1F7 !important;    
  box-shadow: 0 4px 10px rgba(107, 125, 143, 0.12) !important; 

  z-index: 1 !important;                   
  pointer-events: none !important;
  transform: translateY(-3px) translateX(-3px) rotate(-10deg) !important;     
}

/* ==========================================
   六、对方消息左侧：贯穿竖线与圆点 (灰羽蓝)
========================================== */
.msg-avatar-them-container::after,
.msg-bubble-wrapper.msg-them::after {
  display: none !important;
  background: none !important;
}

.msg-bubble-wrapper.msg-them::before {
  content: "" !important;
  position: absolute !important;
  z-index: 10 !important;
  pointer-events: none !important;
  width: 10px !important;            
  transform: translateX(-50%) !important; 
  left: 20px !important; 
}

.msg-bubble-wrapper.msg-them.is-first::before {
  top: -15px !important;             
  bottom: -35px !important; 
  background: linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important; /* 线条变灰羽蓝 */
  background-size: 2px 100% !important;
}

.msg-bubble-wrapper.msg-them.is-mid::before {
  top: -20px !important; 
  bottom: -35px !important; 
  background: linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important;
  background-size: 2px 100% !important;
}

.msg-bubble-wrapper.msg-them.is-last::before {
  top: -20px !important; 
  bottom: 10px !important;           
  background: 
    radial-gradient(circle, #A9B8C6 4px, transparent 4.5px) no-repeat center bottom,
    linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important;
  background-size: 8px 8px, 2px calc(100% - 4px) !important;
}

.msg-bubble-wrapper.msg-them.is-single::before {
  top: -15px !important;             
  bottom: 10px !important; 
  background: 
    radial-gradient(circle, #A9B8C6 4px, transparent 4.5px) no-repeat center bottom,
    linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important;
  background-size: 8px 8px, 2px calc(100% - 4px) !important;
}

/* ==========================================
   七、我方消息右侧：贯穿竖线与顶部圆点 (灰羽蓝)
========================================= */
.msg-avatar-me-container::after,
.msg-bubble-wrapper.msg-me::after {
  display: none !important;
  background: none !important;
}

.msg-bubble-wrapper.msg-me::before {
  content: "" !important;
  position: absolute !important;
  z-index: 10 !important;
  pointer-events: none !important;
  width: 10px !important;            
  transform: translateX(50%) !important;  
  right: 20px !important; 
}

.msg-bubble-wrapper.msg-me.is-first::before {
  top: 10px !important;             
  bottom: -50px !important;          
  background: 
    radial-gradient(circle, #A9B8C6 4px, transparent 4.5px) no-repeat center top,
    linear-gradient(#A9B8C6, #A9B8C6) no-repeat center bottom !important;
  background-size: 8px 8px, 2px calc(100% - 4px) !important;
  background-position: center top, center bottom !important; 
}

.msg-bubble-wrapper.msg-me.is-mid::before {
  top: -20px !important; 
  bottom: -35px !important; 
  background: linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important;
  background-size: 2px 100% !important;
}

.msg-bubble-wrapper.msg-me.is-last::before {
  top: -20px !important; 
  bottom: 30px !important;           
  background: linear-gradient(#A9B8C6, #A9B8C6) no-repeat center top !important;
  background-size: 2px 100% !important;
}

.msg-bubble-wrapper.msg-me.is-single::before {
  top: 5px !important;             
  bottom: -20px !important;           
  background: 
    radial-gradient(circle, #A9B8C6 4px, transparent 4.5px) no-repeat center top,
    linear-gradient(#A9B8C6, #A9B8C6) no-repeat center bottom !important;
  background-size: 8px 8px, 2px calc(100% - 4px) !important;
  background-position: center top, center bottom !important; 
}

/* ==========================================
   八、双方头像旁侧标签 (深雨蓝字)
========================================== */
.msg-avatar-me-inner,
.msg-avatar-them-inner {
  overflow: hidden !important;           
  border-radius: 12px !important;
}

.msg-avatar-them-container::after {
  display: block !important;
  content: "죽음" !important;
  position: absolute !important;
  white-space: nowrap !important;
  z-index: 10 !important;
  top: -3px !important;                  
  left: 45px !important;                 
  font-size: 13px !important;            
  font-weight: bold !important;          
  color: #6B7D8F !important;             
}

.msg-bubble-wrapper.msg-them.is-first::after,
.msg-bubble-wrapper.msg-them.is-single::after {
  display: block !important;
  content: "謊話要用左耳聽" !important;
  position: absolute !important;
  white-space: nowrap !important;
  z-index: 10 !important;
  top: -25px !important;       
  left: 75px !important;       
  font-size: 11px !important;            
  font-weight: normal !important;        
  color: #6B7D8F !important;             
}


/* ==========================================
   十、终极缩减版：隐藏聊天记录中间的独立时间戳
========================================== */
.timestamp, .chat-time, .message-date, .date-divider, .system-message, .chat-system-message, .msg-date, .im-message-date, .chat-message-date-divider,
div[class*="timestamp" i], div[class*="Divider" i], div[class*="TimeDivider" i] {
  display: none !important;
  opacity: 0 !important;
  height: 0 !important;
  margin: 0 !important;
  padding: 0 !important;
  pointer-events: none !important;
}

/* ==========================================
   十一至十四：顶栏重构 (高度、浅云灰背景、头像昵称居中、设置图片)
========================================== */
.chat-header-custom, 
.glass-header {
  height: 70px !important;               
  background-color: #F0F4FA !important;  /* 微带蓝调的浅冷灰 */
  background-image: none !important;     
  border: none !important;               
  box-shadow: none !important;           
  backdrop-filter: none !important;      
  -webkit-backdrop-filter: none !important;
  overflow: visible !important;          
}

.chat-header-subtitle {
  display: none !important;
}

.header-profile-section {
  position: absolute !important;
  left: 50% !important;
  top: 50% !important;
  transform: translate(-50%, -50%) !important; 
  display: flex !important;
  flex-direction: column-reverse !important;   
  align-items: center !important;              
  justify-content: center !important;
  background: transparent !important;
  overflow: visible !important;                
}

.chat-header-title {
  position: relative !important;
  z-index: 10 !important;                
  background: transparent !important;    
  border: none !important;
  padding: 0 !important;
  margin-bottom: 2px !important;         
  top: 16px !important;                   
  left: 0px !important;                  
  font-size: 15px !important;            
  font-weight: bold !important;          
  color: #354454 !important;             /* 顶栏昵称变深海蓝 */
}

.header-avatar-container {
  position: relative !important;
  overflow: visible !important;          
  z-index: 5 !important;
  top: 10px !important;                  
  left: 0px !important;                  
  width: 58px !important;
  height: 58px !important;
  border: none !important;               
  box-shadow: none !important;           
  background: transparent !important;
}

.header-avatar-container img,
.header-avatar-container > div,
.chat-header-avatar {
  display: block !important;
  position: relative !important;
  z-index: 2 !important;                 
  width: 100% !important;
  height: 100% !important;
  object-fit: cover !important;          
  border: none !important;               
  border-radius: 50% !important;         
  overflow: hidden !important;           
}

.header-avatar-container::after {
  content: "" !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  z-index: 3 !important;                 
  pointer-events: none !important;       
  border: 2px solid #FFFFFF !important;  
  box-shadow: 0 2px 8px rgba(107, 125, 143, 0.18) !important; 
  border-radius: 50% !important;         
}

.header-btn-phone, 
.header-btn-video {
  opacity: 0 !important;                 
  pointer-events: auto !important;       
  background: transparent !important;
}

.header-btn-info {
  background-image: url("https://img.cdn1.vip/i/6a41180f44534_1782650895.png") !important;
  background-size: contain !important;   
  background-position: center !important;
  background-repeat: no-repeat !important;
  background-color: transparent !important;
  opacity: 1 !important;                 
  border: none !important;
  width: 24px !important;                
  height: 24px !important;
}

.header-btn-info svg {
  display: none !important;
}

.header-avatar-container::before {
  content: "" !important;
  position: absolute !important;
  z-index: 1 !important;                 
  background-color: #F0F4FA !important;  
  width: 100px !important;               
  height: 100px !important;              
  left: 50% !important;
  transform: translateX(-50%) !important;
  top: -35px !important;                 
  border-radius: 50% !important;         
}

/* ==========================================
   十五、底栏整体与输入框压扁样式
========================================== */
.input-area-custom {
  background: transparent !important;
  background-image: none !important;
  border-top: none !important;           
  box-shadow: none !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

.input-row-wrapper {
  position: relative !important;
  padding-right: 45px !important;        
}

.input-action-bar-custom {
  background-color: #EBF0F6 !important;  /* 输入框背景变浅灰蓝 */
  border: none !important;               
  box-shadow: none !important;
  min-height: 32px !important;           
  height: auto !important;               
  border-radius: 10px !important;        
  padding-left: 32px !important;
  padding-right: 54px !important;
  display: flex !important;
  align-items: center !important;
  position: relative !important;         
}

.input-box-custom {
  background: transparent !important;    
  border: none !important;
  box-shadow: none !important;
  height: auto !important; 
  min-height: 20px !important;           
  font-size: 13.5px !important;          
  line-height: 1.2 !important;
  padding: 6px 0 !important;             
  width: 100% !important;
  caret-color: #354454 !important;       /* 光标变深海蓝 */
}

/* ==========================================
   十六、底栏按钮：内部隐身 + 外部独立 AI GIF 贴图
========================================== */
.input-btn-plus {
  position: absolute !important;
  left: 6px !important;                  
  top: 50% !important;
  transform: translateY(-50%) !important;
  z-index: 10 !important;
  opacity: 0 !important;                 
  pointer-events: auto !important;       
  width: 24px !important;
  height: 24px !important;
  background: transparent !important;
  border: none !important;
}

.input-btn-mic {
  position: absolute !important;
  right: 28px !important;                
  top: 50% !important;
  transform: translateY(-50%) !important;
  z-index: 10 !important;
  opacity: 0 !important;                 
  pointer-events: auto !important;       
  width: 20px !important;
  height: 20px !important;
  background: transparent !important;
  border: none !important;
}

.input-btn-sticker {
  position: absolute !important;
  right: 6px !important;                 
  top: 50% !important;
  transform: translateY(-50%) !important;
  z-index: 10 !important;
  opacity: 0 !important;                 
  pointer-events: auto !important;       
  width: 20px !important;
  height: 20px !important;
  background: transparent !important;
  border: none !important;
}

.input-btn-ai {
  position: absolute !important;
  z-index: 15 !important;
  right: -38px !important;               
  top: 50% !important;
  transform: translateY(-50%) !important;
  width: 34px !important;
  height: 34px !important;
  background-image: url("https://img.cdn1.vip/i/6a413b8bbacb8_1782659979.gif") !important;
  background-repeat: no-repeat !important;
  background-position: center !important; 
  background-size: 24px 20px !important; 
  background-color: transparent !important;
  border: none !important;
  box-shadow: none !important;
  opacity: 1 !important;                 
}

.input-btn-ai svg {
  display: none !important;
}

/* ==========================================
   十八、底栏与底部屏幕边缘的间距调整 
========================================== */
.input-area-custom {
  padding-bottom: calc(env(safe-area-inset-bottom, 0px) + 15px) !important;
}

/* ==========================================
   十九、隐藏输入框内部默认的占位符 
========================================== */
.input-box-custom::placeholder {
  color: transparent !important;
  opacity: 0 !important;
  -webkit-text-fill-color: transparent !important; 
}
.input-box-custom::-webkit-input-placeholder {
  color: transparent !important;
  opacity: 0 !important;
  -webkit-text-fill-color: transparent !important;
}
.input-box-custom::-moz-placeholder {
  color: transparent !important;
  opacity: 0 !important;
}
.input-box-custom:-ms-input-placeholder {
  color: transparent !important;
  opacity: 0 !important;
}

/* ==========================================
   二十、底栏提示栏变灰无边框 (配置同步)
========================================== */
:root {
  --sendas-char-bg: #EBF0F6;             
  --sendas-char-color: #354454;          
  --sendas-char-border: none;            
  --sendas-bar-radius: 10px;             
  --sendas-bar-shadow: none;             
  --sendas-close-color: #6B7D8F;         
}

.input-sendas-bar,
.input-sendas-char-bar,
.input-sendas-narration-bar,
.input-reply-preview-bar {
  background-color: #EBF0F6 !important;  
  background-image: none !important;
  border: none !important;               
  box-shadow: none !important;
  border-radius: 10px !important;        
}

.input-sendas-label,
.input-reply-preview-name {
  color: #354454 !important;             
  font-weight: bold !important;
}

.input-sendas-close,
.input-reply-preview-close {
  color: #6B7D8F !important;             
}

/* ==========================================
   二十一、输入框光标 + 经典晴空蓝发送按钮 
========================================== */
.input-box-custom {
  padding: 6px 0 6px 8px !important; 
}

.send-btn-custom {
  position: absolute !important;
  right: 6px !important;                 
  top: 50% !important;
  transform: translateY(-50%) !important;
  z-index: 20 !important;
  width: 46px !important;                
  height: 24px !important;               
  background-color: #8CA0BA !important;  /* 按钮底色变灰羽蓝 */
  border-radius: 6px !important;         
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

.send-btn-custom svg,
.send-btn-custom img {
  display: none !important;
}

.send-btn-custom::after {
  content: "发送" !important;
  color: #FFFFFF !important;             /* 文字纯白 */
  font-size: 12px !important;
  font-weight: bold !important;
  letter-spacing: 2px !important;        
  margin-right: -2px !important;         
}

/* ==========================================
   二十二、双方自己发信息不同时间的消息间距调整
========================================== */
.msg-bubble-wrapper.msg-me:has(+ [class*="timestamp" i] + .msg-bubble-wrapper.msg-me),
.msg-bubble-wrapper.msg-me:has(+ [class*="date" i] + .msg-bubble-wrapper.msg-me),
.msg-bubble-wrapper.msg-me:has(+ .timestamp-custom + .msg-bubble-wrapper.msg-me) {
  margin-bottom: 20px !important; 
}

.msg-bubble-wrapper.msg-them:has(+ [class*="timestamp" i] + .msg-bubble-wrapper.msg-them),
.msg-bubble-wrapper.msg-them:has(+ [class*="date" i] + .msg-bubble-wrapper.msg-them),
.msg-bubble-wrapper.msg-them:has(+ .timestamp-custom + .msg-bubble-wrapper.msg-them) {
  margin-bottom: 20px !important; 
}

[class*="timestamp" i] + .msg-bubble-wrapper.msg-me,
[class*="date" i] + .msg-bubble-wrapper.msg-me,
.timestamp-custom + .msg-bubble-wrapper.msg-me {
  margin-top: 20px !important;
}

[class*="timestamp" i] + .msg-bubble-wrapper.msg-them,
[class*="date" i] + .msg-bubble-wrapper.msg-them,
.timestamp-custom + .msg-bubble-wrapper.msg-them {
  margin-top: 20px !important;
}

/* ==========================================
   二十三、语音气泡缩小与直展排版 (雨霁蓝主题适配)
========================================== */
:root {
  --voice-play-btn-size: 24px;
  --voice-waveform-height: 20px;
  --voice-duration-size: 10.5px;
  --voice-controls-gap: 6px;
  --voice-toggle-display: flex;
  --voice-transcription-bg: transparent; 
  --voice-transcription-padding: 8px 0 0 0; 
  --voice-transcription-margin-top: 6px; 
  --voice-transcription-size: 13px;      
}

.voice-controls-row {
  position: relative !important;
}

.voice-play-btn {
  position: relative !important;
  z-index: 20 !important;                
}

.voice-transcription-toggle {
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;                
  height: 100% !important;               
  z-index: 10 !important;                
  opacity: 0 !important;                 
  margin: 0 !important;
  padding: 0 !important;
}

.voice-transcription-toggle svg,
.voice-transcription-toggle span,
.voice-transcription-toggle::after,
.voice-transcription-toggle::before {
  display: none !important;
}

.voice-transcription {
  border-top: 1px dashed #E2EAF2 !important; 
  border-radius: 0 !important;           
}

.msg-me .voice-transcription {
  /* 我方气泡背景变为了浅蓝色，分割虚线调整为精致的半透明深海蓝灰虚线 */
