  margin-top: 40px !important; 
}

/* 2. 【我方消息】：给底部留出空间，完美容纳往下掉的头像 */
.msg-bubble-wrapper.msg-me.is-last,
.msg-bubble-wrapper.msg-me.is-single {
  /* ▼ 这里的 42px 必须与您给我方头像设的 top: 40px 大小相匹配 */
  margin-bottom: 40px !important; 
