right: 52px !important; 
}
.input-btn-sticker {
right: 10px !important; 
}/* === 星星魔法核心 === */
/* 1. 屏蔽原生图标 */
.input-btn-plus svg, .input-btn-ai svg, .send-btn-custom svg {
opacity: 0 !important;
}
/* 2. 加号键：永远是实心星星，并暴力向上移 */
.input-btn-plus {
background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23F4E9D9'><path d='M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z'/></svg>") !important;
background-size: 26px !important;
background-repeat: no-repeat !important;
background-position: center !important;
}
/* 3. 发送键：实心星星，去底色 */
.send-btn-custom {
background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23F4E9D9'><path d='M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z'/></svg>") !important;
background-size: 26px !important;
