right: 60px !important; 
background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%23F4E9D9' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'><polygon points='12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2'/></svg>") !important;
background-size: 24px !important; 
z-index: 10 !important;

}
/* === 语音和表情的双拼悬浮小胶囊（终极版） === */
/* 1. 隐藏原生图标 */
.input-btn-mic svg, .input-btn-sticker svg {
display: none !important;
}
/* 2. 语音键（左半边） */
.input-btn-mic {
position: absolute !important;
top: -55px !important; 
right: 60px !important; 
background: rgba(255, 255, 255, 0.6) !important; 
backdrop-filter: blur(10px) !important;
-webkit-backdrop-filter: blur(10px) !important;
border: 1px solid #f5f2e6 !important; 
border-radius: 20px 0 0 20px !important;
width: 50px !important;
height: 24px !important;
box-shadow: -2px 2px 6px rgba(0,0,0,0.02) !important;
transform: translateX(10px) !important;
}
.input-btn-mic::after {
content: "Voice";
font-size: 10px;
color: #d4c394;
position: absolute;
top: 50%; left: 50%;
transform: translate(-50%, -50%);
}
/* 3. 表情键（右半边） */
.input-btn-sticker {
position: absolute !important;
top: -55px !important;
right: 10px !important;
background: rgba(255, 255, 255, 0.6) !important;
backdrop-filter: blur(10px) !important;
-webkit-backdrop-filter: blur(10px) !important;
border: 1px solid #f5f2e6 !important;
border-left: none !important; 
border-radius: 0 20px 20px 0 !important;
width: 50px !important;
height: 24px !important;
box-shadow: 2px 2px 6px rgba(0,0,0,0.02) !important;
transform: translateX(10px) !important;
}
.input-btn-sticker::after {
content: "Memes";
font-size: 10px;
color: #d4c394;
position: absolute;
top: 50%; left: 50%;
transform: translate(-50%, -50%);
}

/* 解决打字时字和星星重叠 */
.input-action-bar-custom:has(.input-box-custom:not(:placeholder-shown)) .input-box-custom {
padding-right: 52px !important;
}
/* 1. 左边星星往上提一点，让它视觉居中 */
.input-btn-plus {
transform: translate(2px, -3px) !important; 
}
/* 2. 胶囊整体往左挪，修正偏右的问题 */
.input-action-bar-custom {
transform: translateX(-4px) !important; 
}
/* === 控制台专属配色（作者原味版） === */
.nuo-console-toggle-bar, .nuo-console-toggle-btn {
--console-toggle-bg: #fcf9f2;
--console-toggle-color: #827762;
}
.nuo-console-panel {
--console-panel-bg: rgba(252, 249, 242, 0.96);
--console-panel-color: #827762;
}
/* 层级稍微压低一点，免得打架 */
.nuo-console-shell {
--console-shell-z: 10;
}

/* === 2. 我方最后一条消息智能避让胶囊 === */
/* 只有在输入框为空（胶囊存在）时，才往上顶。打字时胶囊消失，气泡自动掉下来 */
.chat-detail-screen:has(.input-box-custom:placeholder-shown) [data-absolute-last="true"][data-sender="me"] {
margin-bottom: 30px !important; 
}
/* === 2. 胶囊智能躲避：让 CSS 自己做加法（修复重叠bug） === */
.chat-detail-screen {
--offset-reply: 0px;
--offset-sendas-char: 0px;
--offset-sendas-narr: 0px;
--offset-console: 0px;
}
/* 各自独立报身高，绝不混淆 */
.chat-detail-screen:has(.input-reply-preview-bar) { --offset-reply: 50px; }
.chat-detail-screen:has(.input-sendas-char-bar) { --offset-sendas-char: 40px; }
.chat-detail-screen:has(.input-sendas-narration-bar) { --offset-sendas-narr: 40px; }
.chat-detail-screen:has(.nuo-console-shell) { --offset-console: 45px; }
/* 胶囊自动往上飞，高度 = 所有出现的条的高度总和 */
.input-btn-mic, .input-btn-sticker {
margin-top: calc(-1 * (var(--offset-reply) + var(--offset-sendas-char) + var(--offset-sendas-narr) + var(--offset-console))) !important;
/* 胶囊自动往上飞，并强行统一两半边的动画 */
.input-btn-mic, .input-btn-sticker {
margin-top: calc(-1 * (var(--offset-reply) + var(--offset-sendas-char) + var(--offset-sendas-narr) + var(--offset-console))) !important;
transition: all 0.2s cubic-bezier(0.25, 0.8, 0.25, 1) !important;}
}
/* 控制台出现时，保证胶囊在最上层不被盖住 */
.chat-detail-screen:has(.nuo-console-shell) .input-btn-mic,
.chat-detail-screen:has(.nuo-console-shell) .input-btn-sticker {
z-index: 50 !important;
}

/* === 3. 我方气泡避让胶囊 === */
/* 没打字（胶囊在）时，气泡往上躲 30px；一打字（胶囊消失），气泡自动掉下来 */
.chat-detail-screen:has(.input-box-custom:placeholder-shown) [data-absolute-last="true"][data-sender="me"] {
margin-bottom: 30px !important;
transition: margin-bottom 0.2s ease !important; 
}
/* === 气泡底部便签虚线（首尾封边 + 左右分色版） === */
/* 1. 给第一条、最后一条、单条气泡腾出底部空间 */
.msg-bubble-wrapper.is-first .bubble-them-custom,
.msg-bubble-wrapper.is-last .bubble-them-custom,
.msg-bubble-wrapper.is-single .bubble-them-custom,
.msg-bubble-wrapper.is-first .bubble-me-custom,
.msg-bubble-wrapper.is-last .bubble-me-custom,
.msg-bubble-wrapper.is-single .bubble-me-custom {
position: relative !important;
padding-bottom: 10px !important;
}

/* 2. 对方气泡（左边）的虚线：稍微加深一点的灰（用半透明黑） */
.msg-bubble-wrapper.is-first .bubble-them-custom::after,
.msg-bubble-wrapper.is-last .bubble-them-custom::after,
.msg-bubble-wrapper.is-single .bubble-them-custom::after {
content: "";
position: absolute;
left: 12px;
right: 12px;
bottom: 7px;
border-bottom: 1px dashed rgba(0, 0, 0, 0.12) !important; 
pointer-events: none;
}
/* 3. 我方气泡（右边）的虚线：专属奶黄加透明度 */
.msg-bubble-wrapper.is-first .bubble-me-custom::after,
.msg-bubble-wrapper.is-last .bubble-me-custom::after,
.msg-bubble-wrapper.is-single .bubble-me-custom::after {
content: "";
position: absolute;
left: 12px;
right: 12px;
bottom: 7px;
border-bottom: 1px dashed rgba(212, 195, 148, 0.6) !important; 
pointer-events: none;
}
/* === 独立翻译条（往内缩 + 奶黄统一版） === */
:root {
--translation-always-show: 1;
}
.msg-translation-wrapper { display: none !important; }

.msg-translation-detached {
display: block !important;
margin-top: 4px !important;
}

/* 对方的翻译整体往右挪一点 */
.msg-translation-detached-them {
margin-left: 4px !important; 
}

/* 文字变成浅奶黄 */
.msg-translation-detached-content {
background: transparent !important;
color: #EBDFC1 !important; 
padding: 4px 0 4px 12px !important;
font-size: 13px !important;
position: relative !important;
box-shadow: none !important;
}

/* 竖条也变成一样的浅奶黄 */
.msg-translation-detached-content::before {
content: "" !important;
position: absolute !important;
left: 0 !important;
top: 6px !important;
bottom: 6px !important;
width: 4px !important;
border-radius: 4px !important;
background-color: #EBDFC1 !important; 
}

/* 把装了图片/表情包的气泡背景和边框变透明（排除引用框里的图片） */
.bubble-me-custom:has(img:not(.msg-reply-block-detached img):not(.msg-reply-block img)),
.bubble-them-custom:has(img:not(.msg-reply-block-detached img):not(.msg-reply-block img)) {
background: transparent !important;
border: none !important;
box-shadow: none !important;
padding: 0 !important;
}
/* 去掉图片/表情包底部的虚线（同样排除） */
.bubble-me-custom:has(img:not(.msg-reply-block-detached img):not(.msg-reply-block img))::after,
.bubble-them-custom:has(img:not(.msg-reply-block-detached img):not(.msg-reply-block img))::after {
display: none !important;
}
/* 控制图片大小 + 修复位置 */
.msg-bubble-container img {
max-width: 110px !important; 
max-height: 170px !important;
width: auto !important;
height: auto !important;
object-fit: contain !important;
border-radius: 8px !important;
}
/* 我发的图片靠右贴头像 */
.msg-me .msg-bubble-container img {
display: block !important;
margin-left: auto !important;
}
/* 对方发的图片靠左贴头像 */
.msg-them .msg-bubble-container img {
display: block !important;
margin-right: auto !important;
}
/* 强制缩小引用框里的图片并裁成正方形 */
.msg-bubble-wrapper .msg-reply-block-detached img,
.msg-reply-detached-text img {
    width: 28px !important;
    height: 28px !important;
    max-width: 28px !important; 
    max-height: 28px !important;
    object-fit: cover !important; 
    aspect-ratio: 1 / 1 !important; 
    border-radius: 3px !important;
    vertical-align: middle !important;
    display: inline-block !important;
    margin: 0 4px !important;
}
/* 引用框内容顶部齐平 */
.msg-reply-block-detached {
    align-items: flex-start !important; 
}
/* 名字稍微往下压一点，和图片视觉边缘对齐 */
.msg-reply-detached-name {
    margin-top: 0px !important; 
}

